// Descoberta de ofertas na Amazon.com.br: página de busca (amazon.com.br/s?k={keyword}) com
// User-Agent de navegador comum (caminho leve, sem bot UA especial — validado em 2026-07-13).
// Diferente do Mercado Livre, a própria página de busca já traz preço atual E preço original
// ("De: R$ X") juntos por item, então não precisa de uma segunda requisição por candidato.
//
// A resposta da Amazon vem comprimida (gzip/br) — o node HTTP Request do n8n descomprime
// automaticamente, então isso só importa se algum dia trocarmos pra fetch cru.
//
// Cada card de produto é delimitado por data-asin="XXXXXXXXXX" no HTML — cortamos o documento
// nesses pontos pra associar nome/preço/imagem corretamente a cada produto (uma regex única sem
// esses limites misturaria preços de produtos diferentes).
const BROWSER_UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36';
const MAX_CANDIDATES_PER_KEYWORD = 20;
const MIN_DISCOUNT_PCT = 20;

function parseBRL(str) {
  return parseFloat(str.replace(/\./g, '').replace(',', '.'));
}

const categories = $input.all().map(item => item.json.keyword);
const results = [];

for (const keyword of categories) {
  let html;
  try {
    html = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.amazon.com.br/s?k=${encodeURIComponent(keyword)}`,
      headers: { 'User-Agent': BROWSER_UA },
    });
  } catch (e) {
    continue;
  }

  const asinPositions = [...html.matchAll(/data-asin="([A-Z0-9]{10})"/g)];
  const chunks = [];
  for (let i = 0; i < asinPositions.length && chunks.length < MAX_CANDIDATES_PER_KEYWORD; i++) {
    const start = asinPositions[i].index;
    const end = i + 1 < asinPositions.length ? asinPositions[i + 1].index : html.length;
    chunks.push({ asin: asinPositions[i][1], html: html.slice(start, end) });
  }

  for (const { asin, html: chunk } of chunks) {
    const originalMatch = chunk.match(/De:\s*R\$\s*([\d.,]+)/);
    if (!originalMatch) continue; // sem desconto ativo nesse item

    const currentMatch = chunk.match(/a-offscreen">R\$\s*([\d.,]+)<\/span>/);
    if (!currentMatch) continue;

    const originalPrice = parseBRL(originalMatch[1]);
    const currentPrice = parseBRL(currentMatch[1]);
    if (!(originalPrice > currentPrice)) continue;

    const discountPct = ((originalPrice - currentPrice) / originalPrice) * 100;
    if (discountPct < MIN_DISCOUNT_PCT) continue;

    const titleMatch = chunk.match(/<img[^>]*alt="([^"]+)"/);
    const imageMatch = chunk.match(/<img[^>]*src="([^"]+)"/);

    results.push({
      json: {
        platform: 'amazon',
        product_id: asin,
        product_url: `https://www.amazon.com.br/dp/${asin}`,
        product_name: titleMatch ? titleMatch[1] : '',
        image_url: imageMatch ? imageMatch[1] : '',
        current_price: currentPrice,
        original_price: originalPrice,
        discount_pct: Math.round(discountPct * 10) / 10,
      },
    });
  }
}

return results;
